DECLARE @NewID INT;

INSERT INTO LeadConduit_Batch_Log (WindowStart, WindowEnd, Last_After_ID, Status, RecordsFetched)
VALUES ('@{pipeline().parameters.p_WindowStart}', '@{pipeline().parameters.p_WindowEnd}', '@{pipeline().parameters.p_LastAfterID}', 'RUNNING', 0);

SET @NewID = SCOPE_IDENTITY();

SELECT @NewID as LogID;

